   221 |   // have a icmp_ne or icmp_eq and whether the true or false val is the zero.
   222 |   bool ShouldNotVal = !TC.isZero();
   223 |   ShouldNotVal ^= Pred == ICmpInst::ICMP_NE;
   224 |   if (ShouldNotVal)
   225 |     V = Builder.CreateXor(V, ValC);
   226 | 
   227 |   return V;
   228 | }
